SET
  @ID_8c023119 = 'F3D2A1B8-9C4E-4E7A-BCDE-1234567ABCDE'
SET
  @Name_8c023119 = N'ListConversationDetailFeedbackStats'
SET
  @CategoryID_8c023119 = '5FB6FAFF-8904-490D-9BEE-CA1FF906BD44'
SET
  @UserQuestion_8c023119 = N'What are the aggregate counts and average for conversation feedback ratings (matching the same filters as the row-level query)?'
SET
  @Description_8c023119 = N'Aggregate companion for ListConversationDetailFeedback. Returns Total, AvgRating, PositiveCount (>=8), and NegativeCount (<=3) over the same filtered universe (StartDate, EndDate, MinRating, MaxRating, AgentID, SearchText). Used by the Agent Feedback admin page to populate the four stat cards.'
SET
  @SQL_8c023119 = N'-- Aggregate stats matching the same filter universe as
-- ListConversationDetailFeedback (the row-level query). Used by the Agent
-- Feedback resource to populate the four stat cards (Total / Avg / %High /
-- %Low) — those need to reflect ALL filtered rows, not just the current page,
-- which is why this lives in a separate query rather than being denormalised
-- onto every paged row.
--
-- Parameters mirror the row query (StartDate, EndDate, MinRating, MaxRating,
-- AgentID, SearchText) — pass identical values so both queries describe the
-- same filtered set.
SELECT
    COUNT(*)                                                              AS Total,
    AVG(CAST(cd.UserRating AS FLOAT))                                     AS AvgRating,
    SUM(CASE WHEN cd.UserRating >= 8 THEN 1 ELSE 0 END)                   AS PositiveCount,
    SUM(CASE WHEN cd.UserRating <= 3 THEN 1 ELSE 0 END)                   AS NegativeCount
FROM [${flyway:defaultSchema}].ConversationDetail cd
LEFT JOIN [${flyway:defaultSchema}].Conversation   c  ON c.ID  = cd.ConversationID
LEFT JOIN [${flyway:defaultSchema}].[User]         cu ON cu.ID = c.UserID
LEFT JOIN [${flyway:defaultSchema}].AIAgent        a  ON a.ID  = cd.AgentID
WHERE cd.UserRating IS NOT NULL
    {% if StartDate %}
    AND cd.__mj_UpdatedAt >= {{ StartDate | sqlString }}
    {% endif %}
    {% if EndDate %}
    AND cd.__mj_UpdatedAt <= {{ EndDate | sqlString }}
    {% endif %}
    {% if MinRating %}
    AND cd.UserRating >= {{ MinRating }}
    {% endif %}
    {% if MaxRating %}
    AND cd.UserRating <= {{ MaxRating }}
    {% endif %}
    {% if AgentID %}
    AND cd.AgentID = {{ AgentID | sqlString }}
    {% endif %}
    {% if SearchText %}
    AND (
            cd.UserFeedback   LIKE {{ SearchText | sqlLikeContains }}
         OR cd.Message        LIKE {{ SearchText | sqlLikeContains }}
         OR a.Name            LIKE {{ SearchText | sqlLikeContains }}
         OR cu.Name           LIKE {{ SearchText | sqlLikeContains }}
         OR cu.Email          LIKE {{ SearchText | sqlLikeContains }}
    )
    {% endif %}
'
SET
  @TechnicalDescription_8c023119 = N'Single aggregate SELECT against ${flyway:defaultSchema}.ConversationDetail WHERE UserRating IS NOT NULL with the same LEFT JOINs and Nunjucks filter blocks as ListConversationDetailFeedback. Returns four scalars in a single row.'
SET
  @Status_8c023119 = N'Approved'
SET
  @QualityRank_8c023119 = 8
SET
  @ExecutionCostRank_8c023119 = 1
SET
  @UsesTemplate_8c023119 = 1
SET
  @AuditQueryRuns_8c023119 = 0
SET
