DECLARE @ID_4ec812fb UNIQUEIDENTIFIER,
@Name_4ec812fb NVARCHAR(255),
@CategoryID_4ec812fb UNIQUEIDENTIFIER,
@UserQuestion_4ec812fb NVARCHAR(MAX),
@Description_4ec812fb NVARCHAR(MAX),
@SQL_4ec812fb NVARCHAR(MAX),
@TechnicalDescription_4ec812fb NVARCHAR(MAX),
@OriginalSQL_4ec812fb NVARCHAR(MAX),
@Feedback_4ec812fb NVARCHAR(MAX),
@Status_4ec812fb NVARCHAR(15),
@QualityRank_4ec812fb INT,
@ExecutionCostRank_4ec812fb INT,
@UsesTemplate_4ec812fb BIT,
@AuditQueryRuns_4ec812fb BIT,
@CacheEnabled_4ec812fb BIT,
@CacheTTLMinutes_4ec812fb INT,
@CacheMaxSize_4ec812fb INT,
@EmbeddingVector_4ec812fb NVARCHAR(MAX),
@EmbeddingModelID_4ec812fb UNIQUEIDENTIFIER,
@CacheValidationSQL_4ec812fb NVARCHAR(MAX),
@SQLDialectID_4ec812fb UNIQUEIDENTIFIER,
@Reusable_4ec812fb BIT
SET
  @ID_4ec812fb = 'FACEF5AC-C979-4944-B41F-2BD2A20BEAE7'
SET
  @Name_4ec812fb = N'ListConversationDetailFeedback'
SET
  @CategoryID_4ec812fb = '5FB6FAFF-8904-490D-9BEE-CA1FF906BD44'
SET
  @UserQuestion_4ec812fb = N'What user ratings and feedback have been left on AI messages?'
SET
  @Description_4ec812fb = N'Lists 1-10 user ratings and free-form feedback on conversation messages, joined with the rater (User), conversation, and agent name. Supports time-range, rating-band, and agent filters.'
SET
  @SQL_4ec812fb = N'-- List Conversation Detail Feedback — 1-10 ratings + free-form comments left
-- on AI messages. Used by the Agent Feedback resource. Filtering happens
-- server-side; pagination is delegated to RunQuery via StartRow/MaxRows.
--
-- Parameters (all optional, all wired via Nunjucks):
--   StartDate  : ISO date string lower bound on __mj_UpdatedAt
--   EndDate    : ISO date string upper bound on __mj_UpdatedAt
--   MinRating  : integer 1-10 lower bound
--   MaxRating  : integer 1-10 upper bound
--   AgentID    : scope to a single agent
--   SearchText : case-insensitive substring match across comments, message,
--                agent name, rater name, and rater email
--
-- Storage: ratings live directly on ${flyway:defaultSchema}.ConversationDetail.UserRating +
-- UserFeedback (single rating per message). __mj_UpdatedAt is the "rated at"
-- timestamp.
--
-- Rater attribution: there is no per-rating "rated by" column. Server-side
-- write authorization (MJConversationDetailEntityExtended.currentUserMayWrite)
-- only allows the conversation owner to set UserRating/UserFeedback, so the
-- rater is — by definition — the parent conversation''s owner. Joining the
-- User table via ConversationDetail.UserID (the message *sender*) would
-- attribute the rating to the AI message''s owner (often the system or the
-- conversation owner depending on how the chat writes AI rows), which is
-- semantically wrong.
SELECT
    cd.ID                AS RatingID,
    cd.UserRating        AS Rating,
    cd.UserFeedback      AS Comments,
    cd.__mj_UpdatedAt    AS RatedAt,

    c.UserID             AS RaterUserID,
    cu.Name              AS RaterName,
    cu.Email             AS RaterEmail,

    cd.ID                AS ConversationDetailID,
    cd.ConversationID    AS ConversationID,
    cd.Message           AS MessageText,
    cd.Role              AS MessageRole,
    cd.__mj_CreatedAt    AS MessageCreatedAt,

    c.Name               AS ConversationName,

    cd.AgentID           AS AgentID,
    a.Name               AS AgentName
FROM [${flyway:defaultSchema}].ConversationDetail cd
LEFT JOIN [${flyway:defaultSchema}].Conversation   c  ON c.ID  = cd.ConversationID
LEFT JOIN [${flyway:defaultSchema}].[User]         cu ON cu.ID = c.UserID
LEFT JOIN [${flyway:defaultSchema}].AIAgent        a  ON a.ID  = cd.AgentID
WHERE cd.UserRating IS NOT NULL
    {% if StartDate %}
    AND cd.__mj_UpdatedAt >= {{ StartDate | sqlString }}
    {% endif %}
    {% if EndDate %}
    AND cd.__mj_UpdatedAt <= {{ EndDate | sqlString }}
    {% endif %}
    {% if MinRating %}
    AND cd.UserRating >= {{ MinRating }}
    {% endif %}
    {% if MaxRating %}
    AND cd.UserRating <= {{ MaxRating }}
    {% endif %}
    {% if AgentID %}
    AND cd.AgentID = {{ AgentID | sqlString }}
    {% endif %}
    {% if SearchText %}
    AND (
            cd.UserFeedback   LIKE {{ SearchText | sqlLikeContains }}
         OR cd.Message        LIKE {{ SearchText | sqlLikeContains }}
         OR a.Name            LIKE {{ SearchText | sqlLikeContains }}
         OR cu.Name           LIKE {{ SearchText | sqlLikeContains }}
         OR cu.Email          LIKE {{ SearchText | sqlLikeContains }}
    )
    {% endif %}
ORDER BY cd.__mj_UpdatedAt DESC
'
SET
  @TechnicalDescription_4ec812fb = N'Queries ${flyway:defaultSchema}.ConversationDetail WHERE UserRating IS NOT NULL. Rater is resolved as the parent conversation''s owner (Conversation.UserID → User) because there is no per-rating UserID column and server-side write rules restrict rating writes to the conversation owner. Also LEFT JOINs ${flyway:defaultSchema}.AIAgent for the agent name. Nunjucks conditionals scope by StartDate/EndDate/MinRating/MaxRating/AgentID. Orders most-recent first by __mj_UpdatedAt.'
SET
